function Badge({ type }) {
  const colors = {
    success: 'green',
    error: 'red',
    warning: 'orange'
  };

  return (
    <span style={{ color: colors[type] || 'gray' }}>
      {type ? type.toUpperCase() : 'UNKNOWN'}
    </span>
  );
}

function App() {
  return (
    <div>
      <Badge type="error" />
      <Badge type="info" />
      <Badge />
    </div>
  );
}
